132	static int write_memory_bank_fabric_bitstream_to_text_file(
133	  std::fstream& fp, const bool& fast_configuration,
134	  const bool& bit_value_to_skip, const FabricBitstream& fabric_bitstream) {
135	  int status = 0;
136	
137	  MemoryBankFabricBitstream fabric_bits_by_addr =
138	    build_memory_bank_fabric_bitstream_by_address(fabric_bitstream);
139	
140	  /* The address sizes and data input sizes are the same across any element,
141	   * just get it from the 1st element to save runtime
142	   */
143	  size_t bl_addr_size = fabric_bits_by_addr.begin()->first.first.size();
144	  size_t wl_addr_size = fabric_bits_by_addr.begin()->first.second.size();
145	  size_t din_size = fabric_bits_by_addr.begin()->second.size();
146	
147	  /* Identify and output bitstream size information */
148	  size_t num_bits_to_skip = 0;
149	  if (true == fast_configuration) {
150	    num_bits_to_skip =
151	      fabric_bits_by_addr.size() -
152	      find_memory_bank_fast_configuration_fabric_bitstream_size(
153	        fabric_bitstream, bit_value_to_skip);
154	    VTR_ASSERT(num_bits_to_skip < fabric_bits_by_addr.size());
155	    VTR_LOG(
156	      "Fast configuration will skip %g% (%lu/%lu) of configuration "
157	      "bitstream.\n",
158	      100. * (float)num_bits_to_skip / (float)fabric_bits_by_addr.size(),
159	      num_bits_to_skip, fabric_bits_by_addr.size());
160	  }
161	
162	  /* Output information about how to intepret the bitstream */
163	  fp << "// Bitstream length: " << fabric_bits_by_addr.size() - num_bits_to_skip
164	     << std::endl;
165	  fp << "// Bitstream width (LSB -> MSB): ";
166	  fp << "<bl_address " << bl_addr_size << " bits>";
167	  fp << "<wl_address " << wl_addr_size << " bits>";
168	  fp << "<data input " << din_size << " bits>";
169	  fp << std::endl;
170	
171	  for (const auto& addr_din_pair : fabric_bits_by_addr) {
172	    /* When fast configuration is enabled,
173	     * the rule to skip any configuration bit should consider the whole data
174	     * input values. Only all the bits in the din port match the value to be
175	     * skipped, the programming cycle can be skipped!
176	     */
177	    if (true == fast_configuration) {
178	      if (addr_din_pair.second ==
179	          std::vector<bool>(addr_din_pair.second.size(), bit_value_to_skip)) {
180	        continue;
181	      }
182	    }
183	
184	    /* Write BL address code */
185	    fp << addr_din_pair.first.first;
186	    /* Write WL address code */
187	    fp << addr_din_pair.first.second;
188	    /* Write data input */
189	    for (const bool& din_value : addr_din_pair.second) {
190	      fp << din_value;
191	    }
192	    fp << std::endl;
193	  }
194	
195	  return status;
196	}
