248	/********************************************************************
249	 * Write the fabric bitstream fitting a memory bank protocol
250	 * to a plain text file in efficient method
251	 *
252	 * Old function is write_memory_bank_flatten_fabric_bitstream_to_text_file()
253	 *
254	 * As compared to original function, based on 100K LE FPGA:
255	 *  1. Original function used 600 seconds and needs high memory usage
256	 *  2. This new function only needs 1 second and 4M Bytes
257	 *
258	 * Old function only print WL in decremental order. It is not by intentional
259	 * It is because of the map-key ordering
260	 * In QL Memory Bank with Flatten BL/WL, data is stored by WL address,
261	 *   where we use WL string as map key
262	 *     WL #0 --- "1000000000000 .... 0000"
263	 *     WL #1 --- "0100000000000 .... 0000"
264	 *     WL #n-1 --- "0000000000000 .... 0001
265	 * From string comparison wise, WL #n-1 will be first, and WL #0 will be last
266	 * The sequence of WL does not really matter,  but preferrable in some ordering
267	 *   manner. Using map key as ordering cannot guarantee the determinstic
268	 *
269	 * This new way of writting fabric guarantee the WL order in 100% deterministc
270	 *   way: either incremental (default) or decremental
271	 *
272	 * Return:
273	 *  - 0 if succeed
274	 *  - 1 if critical errors occured
275	 *******************************************************************/
276	static int fast_write_memory_bank_flatten_fabric_bitstream_to_text_file(
277	  std::fstream& fp, const bool& fast_configuration,
278	  const bool& bit_value_to_skip, const FabricBitstream& fabric_bitstream,
279	  const bool& keep_dont_care_bits, const bool& wl_incremental_order) {
280	  int status = 0;
281	
282	  std::string dont_care_bit = "0";
283	  if (keep_dont_care_bits) {
284	    dont_care_bit = "x";
285	  }
286	  const FabricBitstreamMemoryBank& memory_bank =
287	    fabric_bitstream.memory_bank_info(fast_configuration, bit_value_to_skip);
288	
289	  fabric_size_t longest_effective_wl_count =
290	    memory_bank.get_longest_effective_wl_count();
291	  /* Output information about how to intepret the bitstream */
292	  fp << "// Bitstream length: " << longest_effective_wl_count << std::endl;
293	  fp << "// Bitstream width (LSB -> MSB): ";
294	  fp << "<bl_address " << memory_bank.get_total_bl_addr_size() << " bits>";
295	  fp << "<wl_address " << memory_bank.get_total_wl_addr_size() << " bits>";
296	  fp << std::endl;
297	
298	  // Step 1
299	  // Initialize wl_indexes for every region
300	  // The intialization depends the ordering of WL
301	  // It could either be 0 (if wl_incremental_order=true) or
302	  // last WL index (if wl_incremental_order=false)
303	  std::vector<fabric_size_t> wl_indexes;
304	  for (size_t region = 0; region < memory_bank.datas.size(); region++) {
305	    if (wl_incremental_order) {
306	      wl_indexes.push_back(0);
307	    } else {
308	      wl_indexes.push_back(
309	        (fabric_size_t)(memory_bank.datas[region].size() - 1));
310	    }
311	  }
312	  // Step 2
313	  // Loop through total WL count that we would like to configure
314	  for (size_t wl_index = 0; wl_index < longest_effective_wl_count; wl_index++) {
315	    // Step 3
316	    // Write BL address
317	    // We cascade all regions: 0, 1, 2 ...
318	    for (size_t region = 0; region < memory_bank.datas.size(); region++) {
319	      // Step 3a
320	      // The sequence of configuration of each region WL is not the same
321	      //   since WL to skip for each region is not the same
322	      // If it happen that current WL that we are going to program is
323	      //   one of the WLs (stored in wls_to_skip) that we had determined
324	      //   to skip, the we will increment or decrement to next
325	      //   depending on wl_incremental_order
326	      const fabric_blwl_length& lengths = memory_bank.blwl_lengths[region];
327	      fabric_size_t current_wl = wl_indexes[region];
328	      while (std::find(memory_bank.wls_to_skip[region].begin(),
329	                       memory_bank.wls_to_skip[region].end(),
330	                       current_wl) != memory_bank.wls_to_skip[region].end()) {
331	        // We would like to skip this
332	        if (wl_incremental_order) {
333	          wl_indexes[region]++;
334	        } else {
335	          wl_indexes[region]--;
336	        }
337	        current_wl = wl_indexes[region];
338	      }
339	      // Step 3b
340	      // If current WL still within the valid range, we will print BL
341	      // Otherwise it is either
342	      //   overflow (wl_incremental_order=true) or
343	      //   underflow (to max fabric_blwl_length when wl_incremental_order=false)
344	      // Since fabric_blwl_length is unsigned, hence underflow of -1 will be
345	      //   considered as overflow too
346	      // If it is overflow/underflow, then we just print don't care
347	      if (current_wl < memory_bank.datas[region].size()) {
348	        const std::vector<uint8_t>& data =
349	          memory_bank.datas[region][current_wl];
350	        const std::vector<uint8_t>& mask =
351	          memory_bank.masks[region][current_wl];
352	        // Step 3c
353	        // Real code to print BL data that we had stored
354	        // mask tell you each BL is valid
355	        //   for invalid BL, we will print don't care
356	        // data tell you the real din value
357	        // (bl >> 3) - This is to find Byte index of the BL
358	        // (1 << (bl & 7)) - This is to find Bit index of the BL
359	        //                   within that Byte index
360	        // When we '&' both, we can know if that BL is set or unset
361	        /*
362	          -----------------------------------------------------------------
363	          |  bit (bl)  |  Byte index (bl >> 3) | Bit index (1 << (bl & 7)) |
364	          |----------------------------------------------------------------
365	          |  0         |             0         |    b0000_0001 (or 0x01)   |
366	          |  1         |             0         |    b0000_0010 (or 0x02)   |
367	          |  2         |             0         |    b0000_0100 (or 0x04)   |
368	          |  3         |             0         |    b0000_1000 (or 0x08)   |
369	          |  4         |             0         |    b0001_0000 (or 0x10)   |
370	          |  5         |             0         |    b0010_0000 (or 0x20)   |
371	          |  6         |             0         |    b0100_0000 (or 0x40)   |
372	          |  7         |             0         |    b1000_0000 (or 0x80)   |
373	          |  8         |             1         |    b0000_0001 (or 0x01)   |
374	          | ...        |            ...        |          ...              |
375	          ------------------------------------------------------------------
376	          Each BL can be uniquely represented by bit slice in byte array
377	        */
378	        for (size_t bl = 0; bl < lengths.bl; bl++) {
379	          if (mask[bl >> 3] & (1 << (bl & 7))) {
380	            if (data[bl >> 3] & (1 << (bl & 7))) {
381	              fp << "1";
382	            } else {
383	              fp << "0";
384	            }
385	          } else {
386	            fp << dont_care_bit.c_str();
387	          }
388	        }
389	      } else {
390	        /* However not all region has equal WL, for those that is shorter,
391	         * print 'x' for all BL*/
392	        for (size_t bl = 0; bl < lengths.bl; bl++) {
393	          fp << dont_care_bit.c_str();
394	        }
395	      }
396	    }
397	    // Step 4
398	    // Write WL address
399	    // We cascade all regions: 0, 1, 2 ...
400	    for (size_t region = 0; region < memory_bank.datas.size(); region++) {
401	      const fabric_blwl_length& lengths = memory_bank.blwl_lengths[region];
402	      fabric_size_t current_wl = wl_indexes[region];
403	      // Step 4a
404	      // If current WL still within the valid range, we will print WL
405	      // Otherwise it is overflow/underflow then we will print don't care
406	      if (current_wl < memory_bank.datas[region].size()) {
407	        // Step 4b
408	        // One hot printing
409	        for (size_t wl_temp = 0; wl_temp < lengths.wl; wl_temp++) {
410	          if (wl_temp == current_wl) {
411	            fp << "1";
412	          } else {
413	            fp << "0";
414	          }
415	        }
416	        // Step 4b
417	        // Increment or decrement to next depending on wl_incremental_order
418	        if (wl_incremental_order) {
419	          wl_indexes[region]++;
420	        } else {
421	          wl_indexes[region]--;
422	        }
423	      } else {
424	        /* However not all region has equal WL, for those that is shorter,
425	         * print 'x' for all WL */
426	        for (size_t wl_temp = 0; wl_temp < lengths.wl; wl_temp++) {
427	          fp << dont_care_bit.c_str();
428	        }
429	      }
430	    }
431	    fp << std::endl;
432	  }
433	  return status;
434	}
435	
436	/********************************************************************
437	 * Write the fabric bitstream fitting a memory bank protocol
438	 * to a plain text file
439	 *
440	 * Return:
441	 *  - 0 if succeed
442	 *  - 1 if critical errors occured
443	 *******************************************************************/
444	static int write_memory_bank_shift_register_fabric_bitstream_to_text_file(
445	  std::fstream& fp, const bool& fast_configuration,
446	  const bool& bit_value_to_skip, const FabricBitstream& fabric_bitstream,
447	  const MemoryBankShiftRegisterBanks& blwl_sr_banks,
448	  const bool& keep_dont_care_bits) {
449	  int status = 0;
450	
451	  char dont_care_bit = '0';
452	  if (keep_dont_care_bits) {
453	    dont_care_bit = DONT_CARE_CHAR;
454	  }
455	  MemoryBankShiftRegisterFabricBitstream fabric_bits =
456	    build_memory_bank_shift_register_fabric_bitstream(
457	      fabric_bitstream, blwl_sr_banks, fast_configuration, bit_value_to_skip,
458	      dont_care_bit);
459	
460	  /* Output information about how to intepret the bitstream */
461	  fp << "// Bitstream word count: " << fabric_bits.num_words() << std::endl;
462	  fp << "// Bitstream bl word size: " << fabric_bits.bl_word_size()
463	     << std::endl;
464	  fp << "// Bitstream wl word size: " << fabric_bits.wl_word_size()
465	     << std::endl;
466	  fp << "// Bitstream width (LSB -> MSB): ";
467	  fp << "<bl shift register heads " << fabric_bits.bl_width() << " bits>";
468	  fp << "<wl shift register heads " << fabric_bits.wl_width() << " bits>";
469	  fp << std::endl;
470	
471	  size_t word_cnt = 0;
472	
473	  for (const auto& word : fabric_bits.words()) {
474	    fp << "// Word " << word_cnt << std::endl;
475	
476	    /* Write BL address code */
477	    fp << "// BL part " << std::endl;
478	    for (const auto& bl_vec : fabric_bits.bl_vectors(word)) {
479	      fp << bl_vec;
480	      fp << std::endl;
481	    }
482	
483	    /* Write WL address code */
484	    fp << "// WL part " << std::endl;
485	    for (const auto& wl_vec : fabric_bits.wl_vectors(word)) {
486	      fp << wl_vec;
487	      fp << std::endl;
488	    }
489	
490	    word_cnt++;
491	  }
492	
493	  return status;
494	}
