496	/********************************************************************
497	 * Write the fabric bitstream fitting a frame-based protocol
498	 * to a plain text file
499	 *
500	 * Return:
501	 *  - 0 if succeed
502	 *  - 1 if critical errors occured
503	 *******************************************************************/
504	static int write_frame_based_fabric_bitstream_to_text_file(
505	  std::fstream& fp, const bool& fast_configuration,
506	  const bool& bit_value_to_skip, const FabricBitstream& fabric_bitstream) {
507	  int status = 0;
508	
509	  FrameFabricBitstream fabric_bits_by_addr =
510	    build_frame_based_fabric_bitstream_by_address(fabric_bitstream);
511	
512	  /* The address sizes and data input sizes are the same across any element,
513	   * just get it from the 1st element to save runtime
514	   */
515	  size_t addr_size = fabric_bits_by_addr.begin()->first.size();
516	  size_t din_size = fabric_bits_by_addr.begin()->second.size();
517	
518	  /* Identify and output bitstream size information */
519	  size_t num_bits_to_skip = 0;
520	  if (true == fast_configuration) {
521	    num_bits_to_skip =
522	      fabric_bits_by_addr.size() -
523	      find_frame_based_fast_configuration_fabric_bitstream_size(
524	        fabric_bitstream, bit_value_to_skip);
525	    VTR_ASSERT(num_bits_to_skip < fabric_bits_by_addr.size());
526	    VTR_LOG(
527	      "Fast configuration will skip %g% (%lu/%lu) of configuration "
528	      "bitstream.\n",
529	      100. * (float)num_bits_to_skip / (float)fabric_bits_by_addr.size(),
530	      num_bits_to_skip, fabric_bits_by_addr.size());
531	  }
532	
533	  /* Output information about how to intepret the bitstream */
534	  fp << "// Bitstream length: " << fabric_bits_by_addr.size() - num_bits_to_skip
535	     << std::endl;
536	  fp << "// Bitstream width (LSB -> MSB): <address " << addr_size
537	     << " bits><data input " << din_size << " bits>" << std::endl;
538	
539	  for (const auto& addr_din_pair : fabric_bits_by_addr) {
540	    /* When fast configuration is enabled,
541	     * the rule to skip any configuration bit should consider the whole data
542	     * input values. Only all the bits in the din port match the value to be
543	     * skipped, the programming cycle can be skipped!
544	     */
545	    if (true == fast_configuration) {
546	      if (addr_din_pair.second ==
547	          std::vector<bool>(addr_din_pair.second.size(), bit_value_to_skip)) {
548	        continue;
549	      }
550	    }
551	
552	    /* Write address code */
553	    fp << addr_din_pair.first;
554	
555	    /* Write data input */
556	    for (const bool& din_value : addr_din_pair.second) {
557	      fp << din_value;
558	    }
559	    fp << std::endl;
560	  }
561	
562	  return status;
563	}
564	
565	/********************************************************************
566	 * Write the fabric bitstream to a plain text file
567	 * Notes:
568	 *   - This is the final bitstream which is loadable to the FPGA fabric
569	 *     (Verilog netlists etc.)
570	 *   - Do NOT include any comments or other characters that the 0|1 bitstream
571	 *content in this file
572	 *
573	 * Return:
574	 *  - 0 if succeed
575	 *  - 1 if critical errors occured
576	 *******************************************************************/
577	int write_fabric_bitstream_to_text_file(
578	  const BitstreamManager& bitstream_manager,
579	  const FabricBitstream& fabric_bitstream,
580	  const MemoryBankShiftRegisterBanks& blwl_sr_banks,
581	  const ConfigProtocol& config_protocol,
582	  const FabricGlobalPortInfo& global_ports,
583	  const BitstreamWriterOption& options) {
584	  VTR_ASSERT(options.output_file_type() ==
585	             BitstreamWriterOption::e_bitfile_type::TEXT);
586	  std::string fname = options.output_file_name();
587	  /* Ensure that we have a valid file name */
588	  if (true == fname.empty()) {
589	    VTR_LOG_ERROR(
590	      "Received empty file name to output bitstream!\n\tPlease specify a valid "
591	      "file name.\n");
592	  }
593	
594	  std::string timer_message =
595	    std::string("Write ") + std::to_string(fabric_bitstream.num_bits()) +
596	    std::string(" fabric bitstream into plain text file '") + fname +
597	    std::string("'");
598	  vtr::ScopedStartFinishTimer timer(timer_message);
599	
600	  /* Create the file stream */
601	  std::fstream fp;
602	  fp.open(fname, std::fstream::out | std::fstream::trunc);
603	
604	  check_file_stream(fname.c_str(), fp);
605	
606	  bool apply_fast_configuration =
607	    is_fast_configuration_applicable(global_ports) &&
608	    options.fast_configuration();
609	  if (options.fast_configuration() &&
610	      apply_fast_configuration != options.fast_configuration()) {
611	    VTR_LOG_WARN("Disable fast configuration even it is enabled by user\n");
612	  }
613	
614	  bool bit_value_to_skip = false;
615	  if (apply_fast_configuration) {
616	    bit_value_to_skip = find_bit_value_to_skip_for_fast_configuration(
617	      config_protocol.type(), global_ports, bitstream_manager,
618	      fabric_bitstream);
619	  }
620	
621	  /* Write file head */
622	  write_fabric_bitstream_text_file_head(fp, options.time_stamp());
623	
624	  /* Output fabric bitstream to the file */
625	  int status = 0;
626	  switch (config_protocol.type()) {
627	    case CONFIG_MEM_STANDALONE:
628	      status = write_flatten_fabric_bitstream_to_text_file(
629	        fp, bitstream_manager, fabric_bitstream);
630	      break;
631	    case CONFIG_MEM_SCAN_CHAIN:
632	      status = write_config_chain_fabric_bitstream_to_text_file(
633	        fp, apply_fast_configuration, bit_value_to_skip, bitstream_manager,
634	        fabric_bitstream);
635	      break;
636	    case CONFIG_MEM_QL_MEMORY_BANK: {
637	      /* Bitstream organization depends on the BL/WL protocols
638	       * - If BL uses decoders, we have to config each memory cell one by one.
639	       * - If BL uses flatten, we can configure all the memory cells on the same
640	       * row by enabling dedicated WL In such case, we will merge the BL data
641	       * under the same WL address Fast configuration is applicable when a row
642	       * of BLs are all zeros/ones while we have a global reset/set for all the
643	       * memory cells
644	       * - if BL uses shift-register, same as the flatten.
645	       */
646	      if (BLWL_PROTOCOL_DECODER == config_protocol.bl_protocol_type()) {
647	        status = write_memory_bank_fabric_bitstream_to_text_file(
648	          fp, apply_fast_configuration, bit_value_to_skip, fabric_bitstream);
649	      } else if (BLWL_PROTOCOL_FLATTEN == config_protocol.bl_protocol_type() &&
650	                 BLWL_PROTOCOL_FLATTEN == config_protocol.wl_protocol_type()) {
651	        // If both BL and WL protocols are flatten, use new way to write the
652	        // bitstream
653	        status = fast_write_memory_bank_flatten_fabric_bitstream_to_text_file(
654	          fp, apply_fast_configuration, bit_value_to_skip, fabric_bitstream,
655	          options.keep_dont_care_bits(), !options.wl_decremental_order());
656	
657	      } else if (BLWL_PROTOCOL_FLATTEN == config_protocol.bl_protocol_type()) {
658	        status = write_memory_bank_flatten_fabric_bitstream_to_text_file(
659	          fp, apply_fast_configuration, bit_value_to_skip, fabric_bitstream,
660	          options.keep_dont_care_bits());
661	      } else {
662	        VTR_ASSERT(BLWL_PROTOCOL_SHIFT_REGISTER ==
663	                   config_protocol.bl_protocol_type());
664	        status = write_memory_bank_shift_register_fabric_bitstream_to_text_file(
665	          fp, apply_fast_configuration, bit_value_to_skip, fabric_bitstream,
666	          blwl_sr_banks, options.keep_dont_care_bits());
667	      }
668	      break;
669	    }
670	    case CONFIG_MEM_MEMORY_BANK:
671	      status = write_memory_bank_fabric_bitstream_to_text_file(
672	        fp, apply_fast_configuration, bit_value_to_skip, fabric_bitstream);
673	      break;
674	    case CONFIG_MEM_FRAME_BASED:
675	      status = write_frame_based_fabric_bitstream_to_text_file(
676	        fp, apply_fast_configuration, bit_value_to_skip, fabric_bitstream);
677	      break;
678	    default:
679	      VTR_LOGF_ERROR(__FILE__, __LINE__,
680	                     "Invalid configuration protocol type!\n");
681	      status = 1;
682	  }
683	
684	  /* Print an end to the file here */
685	  fp << std::endl;
686	
687	  /* Close file handler */
688	  fp.close();
689	
690	  VTR_LOGV(options.verbose_output(),
691	           "Outputted %lu configuration bits to plain text file: %s\n",
692	           fabric_bitstream.bits().size(), fname.c_str());
693	
694	  return status;
695	}
696	
697	} /* end namespace openfpga */
