1	/********************************************************************
2	 * This file includes functions that output a fabric-dependent
3	 * bitstream database to files in XML format
4	 *******************************************************************/
5	#include <chrono>
6	#include <ctime>
7	#include <fstream>
8	
9	/* Headers from vtrutil library */
10	#include "vtr_assert.h"
11	#include "vtr_log.h"
12	#include "vtr_time.h"
13	
14	/* Headers from openfpgautil library */
15	#include "openfpga_digest.h"
16	
17	/* Headers from archopenfpga library */
18	
19	#include "bitstream_manager_utils.h"
20	#include "openfpga_naming.h"
21	#include "write_xml_fabric_bitstream.h"
22	
23	/* begin namespace openfpga */
24	namespace openfpga {
25	
26	/********************************************************************
27	 * This function write header information to a bitstream file
28	 *******************************************************************/
29	static void write_fabric_bitstream_xml_file_head(
30	  std::fstream& fp, const bool& include_time_stamp) {
31	  valid_file_stream(fp);
32	
33	  fp << "<!--" << std::endl;
34	  fp << "\t- Fabric bitstream" << std::endl;
35	  fp << "\t- Author: Xifan TANG" << std::endl;
36	  fp << "\t- Organization: University of Utah" << std::endl;
37	
38	  auto end = std::chrono::system_clock::now();
39	  std::time_t end_time = std::chrono::system_clock::to_time_t(end);
40	  if (include_time_stamp) {
41	    fp << "\t- Date: " << std::ctime(&end_time);
42	  }
43	
44	  fp << "-->" << std::endl;
45	  fp << std::endl;
46	}
47	
48	/********************************************************************
49	 * Write a configuration bit into a plain text file
50	 * General format
51	 *   <bit id="<fabric_bit>" value="<config_bit_value>">
52	 *     <hierarchy>
53	 *       <!-- configurable memory hierarchy -->
54	 *     </hierarchy>
55	 *     <!-- address information -->
56	 *     ...
57	 *   </bit>
58	 * The format depends on the type of configuration protocol
59	 * - Vanilla (standalone): No more information to be included
60	 * - Configuration chain: No more information to be included
61	 * - Memory bank :
62	 *     <bl address="<bl_address_value>"/>
63	 *     <wl address="<wl_address_value>"/>
64	 * - Frame-based configuration protocol :
65	 *     <frame address="<frame_address_value>"/>
66	 *
67	 * Return:
68	 *  - 0 if succeed
69	 *  - 1 if critical errors occured
70	 *******************************************************************/
71	static int write_fabric_config_bit_to_xml_file(
72	  std::fstream& fp, const BitstreamManager& bitstream_manager,
73	  const FabricBitstream& fabric_bitstream, const FabricBitId& fabric_bit,
74	  const e_config_protocol_type& config_type, bool fast_xml,
75	  const int& xml_hierarchy_depth, std::string& bl_addr, std::string& wl_addr,
76	  const BitstreamWriterOption& options) {
77	  if (false == valid_file_stream(fp)) {
78	    return 1;
79	  }
80	  if (options.value_to_skip(
81	        bitstream_manager.bit_value(fabric_bitstream.config_bit(fabric_bit)))) {
82	    return 0;
83	  }
84	
85	  write_tab_to_file(fp, xml_hierarchy_depth);
86	  fp << "<bit id=\"" << size_t(fabric_bit) << "\"";
87	  if (options.output_value()) {
88	    fp << " value=\"";
89	    fp << bitstream_manager.bit_value(fabric_bitstream.config_bit(fabric_bit));
90	    fp << "\"";
91	  }
92	
93	  /* Output hierarchy of this parent*/
94	  const ConfigBitId& config_bit = fabric_bitstream.config_bit(fabric_bit);
95	  const ConfigBlockId& config_block =
96	    bitstream_manager.bit_parent_block(config_bit);
97	
98	  if (options.output_path()) {
99	    std::vector<ConfigBlockId> block_hierarchy =
100	      find_bitstream_manager_block_hierarchy(bitstream_manager, config_block);
101	    std::string hie_path;
102	    for (size_t iblk = 0; iblk < block_hierarchy.size(); ++iblk) {
103	      /* If enabled, pop the last block name */
104	      if (options.trim_path() && iblk == block_hierarchy.size() - 1) {
105	        break;
106	      }
107	      hie_path += bitstream_manager.block_name(block_hierarchy[iblk]);
108	      hie_path += std::string(".");
109	    }
110	    hie_path += generate_configurable_memory_data_out_name();
111	    hie_path += std::string("[");
112	    size_t bit_idx_in_parent_block =
113	      find_bitstream_manager_config_bit_index_in_parent_block(bitstream_manager,
114	                                                              config_bit);
115	    if (options.trim_path()) {
116	      bit_idx_in_parent_block =
117	        find_bitstream_manager_config_bit_index_in_grandparent_block(
118	          bitstream_manager, config_bit);
119	    }
120	    hie_path += std::to_string(bit_idx_in_parent_block);
121	    hie_path += std::string("]");
122	
123	    fp << " path=\"" << hie_path << "\"";
124	  }
125	  fp << ">\n";
126	
127	  switch (config_type) {
128	    case CONFIG_MEM_STANDALONE:
129	    case CONFIG_MEM_SCAN_CHAIN:
130	      break;
131	    case CONFIG_MEM_MEMORY_BANK:
132	    case CONFIG_MEM_QL_MEMORY_BANK: {
133	      if (fast_xml) {
134	        // New way of printing XML
135	        // This is fast (less than 100s) as compared to original 1300s seen in
136	        // 100K LE FPFA
137	        const FabricBitstreamMemoryBank& memory_bank =
138	          fabric_bitstream.memory_bank_info();
139	        /* Bit line address */
140	        write_tab_to_file(fp, xml_hierarchy_depth + 1);
141	        const fabric_bit_data& bit =
142	          memory_bank.fabric_bit_datas[(size_t)(fabric_bit)];
143	        const fabric_blwl_length& lengths =
144	          memory_bank.blwl_lengths[bit.region];
145	        if (bl_addr.size() == 0) {
146	          VTR_ASSERT(wl_addr.size() == 0);
147	          bl_addr.resize(lengths.bl);
148	          wl_addr.resize(lengths.wl);
149	          bl_addr.assign(lengths.bl, 'x');
150	          wl_addr.assign(lengths.wl, '0');
151	        } else {
152	          VTR_ASSERT((fabric_size_t)(bl_addr.size()) == lengths.bl);
153	          VTR_ASSERT((fabric_size_t)(wl_addr.size()) == lengths.wl);
154	        }
155	        fp << "<bl address=\"";
156	        bl_addr.replace(bit.bl, 1, "1");
157	        fp << bl_addr.c_str();
158	        bl_addr.replace(bit.bl, 1, "x");
159	        fp << "\"/>\n";
160	        /* Word line address */
161	        write_tab_to_file(fp, xml_hierarchy_depth + 1);
162	        fp << "<wl address=\"";
163	        wl_addr.replace(bit.wl, 1, "1");
164	        fp << wl_addr.c_str();
165	        wl_addr.replace(bit.wl, 1, "0");
166	        fp << "\"/>\n";
167	      } else {
168	        /* Bit line address */
169	        write_tab_to_file(fp, xml_hierarchy_depth + 1);
170	        fp << "<bl address=\"";
171	        for (const char& addr_bit :
172	             fabric_bitstream.bit_bl_address(fabric_bit)) {
173	          fp << addr_bit;
174	        }
175	        fp << "\"/>\n";
176	
177	        write_tab_to_file(fp, xml_hierarchy_depth + 1);
178	        fp << "<wl address=\"";
179	        for (const char& addr_bit :
180	             fabric_bitstream.bit_wl_address(fabric_bit)) {
181	          fp << addr_bit;
182	        }
183	        fp << "\"/>\n";
184	      }
185	      break;
186	    }
187	    case CONFIG_MEM_FRAME_BASED: {
188	      write_tab_to_file(fp, xml_hierarchy_depth + 1);
189	      fp << "<frame address=\"";
190	      for (const char& addr_bit : fabric_bitstream.bit_address(fabric_bit)) {
191	        fp << addr_bit;
192	      }
193	      fp << "\"/>\n";
194	      break;
195	    }
196	    default:
197	      VTR_LOGF_ERROR(__FILE__, __LINE__,
198	                     "Invalid configuration protocol type!\n");
199	      return 1;
200	  }
201	
202	  write_tab_to_file(fp, xml_hierarchy_depth);
203	  fp << "</bit>\n";
204	
205	  return 0;
206	}
207	
208	/********************************************************************
209	 * Write the fabric bitstream in a specific configuration region to an XML file
210	 *
211	 * Return:
212	 *  - 0 if succeed
213	 *  - 1 if critical errors occured
214	 *******************************************************************/
215	static int write_fabric_regional_config_bit_to_xml_file(
216	  std::fstream& fp, const BitstreamManager& bitstream_manager,
217	  const FabricBitstream& fabric_bitstream,
218	  const FabricBitRegionId& fabric_region,
219	  const e_config_protocol_type& config_type, bool fast_xml,
220	  const int& xml_hierarchy_depth, const BitstreamWriterOption& options) {
221	  if (false == valid_file_stream(fp)) {
222	    return 1;
223	  }
224	
225	  int status = 0;
226	  // Use string to print, instead of char by char
227	  // This is for Flatten BL/WL protocol
228	  // You will find this much more faster than char by char
229	  // We do not need to build the string for every BL/WL
230	  // It is one-hot and sequal addr
231	  // We start with all '0' (WL) or 'x' (BL)
232	  // By setting "1' and resettting ('0' or 'x') at approriate bit position
233	  // We could create one-hot string much faster
234	  // Use FPGA 100K as example: old way needs 1300seconds to write 85Gig XML
235	  // New way only needs 80seconds to write identical XML
236	  std::string bl_addr = "";
237	  std::string wl_addr = "";
238	  write_tab_to_file(fp, xml_hierarchy_depth);
239	  fp << "<region ";
240	  fp << "id=\"";
241	  fp << size_t(fabric_region);
242	  fp << "\"";
243	  fp << ">\n";
244	
245	  size_t bit_index = 0;
246	  size_t total_bits = fabric_bitstream.region_bits(fabric_region).size();
247	  size_t percentage = 0;
248	  for (const FabricBitId& fabric_bit :
249	       fabric_bitstream.region_bits(fabric_region)) {
250	    status = write_fabric_config_bit_to_xml_file(
251	      fp, bitstream_manager, fabric_bitstream, fabric_bit, config_type,
252	      fast_xml, xml_hierarchy_depth + 1, bl_addr, wl_addr, options);
253	    if (1 == status) {
254	      return status;
255	    }
256	    // Misc to print percentage of the process
257	    bit_index++;
258	    size_t temp = (bit_index * 100) / total_bits;
259	    if (temp != percentage) {
260	      VTR_LOG("  Progress: %lu%\r", percentage);
261	      percentage = temp;
262	    }
263	  }
264	
265	  write_tab_to_file(fp, xml_hierarchy_depth);
266	  fp << "</region>\n";
267	
268	  return status;
269	}
270	
271	/********************************************************************
272	 * Write the fabric bitstream to an XML file
273	 * Notes:
274	 *   - This file is designed to be reused by testbench generators, e.g., CocoTB
275	 *   - It can NOT be directly loaded to the FPGA fabric
276	 *   - It include configurable memory paths in full hierarchy
277	 *
278	 * Return:
279	 *  - 0 if succeed
280	 *  - 1 if critical errors occured
281	 *******************************************************************/
282	int write_fabric_bitstream_to_xml_file(
283	  const BitstreamManager& bitstream_manager,
284	  const FabricBitstream& fabric_bitstream,
285	  const ConfigProtocol& config_protocol, const BitstreamWriterOption& options) {
286	  VTR_ASSERT(options.output_file_type() ==
287	             BitstreamWriterOption::e_bitfile_type::XML);
288	  /* Ensure that we have a valid file name */
289	  std::string fname = options.output_file_name();
290	  if (true == fname.empty()) {
291	    VTR_LOG_ERROR(
292	      "Received empty file name to output bitstream!\n\tPlease specify a valid "
293	      "file name.\n");
294	  }
295	
296	  std::string timer_message =
297	    std::string("Write ") + std::to_string(fabric_bitstream.num_bits()) +
298	    std::string(" fabric bitstream into xml file '") + fname + std::string("'");
299	  vtr::ScopedStartFinishTimer timer(timer_message);
300	
301	  /* Create the file stream */
302	  std::fstream fp;
303	  fp.open(fname, std::fstream::out | std::fstream::trunc);
304	
305	  check_file_stream(fname.c_str(), fp);
306	
307	  /* Write XML head */
308	  write_fabric_bitstream_xml_file_head(fp, options.time_stamp());
309	
310	  int xml_hierarchy_depth = 0;
311	  fp << "<fabric_bitstream>\n";
312	
313	  /* Output fabric bitstream to the file */
314	  int status = 0;
315	  for (const FabricBitRegionId& region : fabric_bitstream.regions()) {
316	    status = write_fabric_regional_config_bit_to_xml_file(
317	      fp, bitstream_manager, fabric_bitstream, region, config_protocol.type(),
318	      BLWL_PROTOCOL_FLATTEN == config_protocol.bl_protocol_type() &&
319	        BLWL_PROTOCOL_FLATTEN == config_protocol.wl_protocol_type(),
320	      xml_hierarchy_depth + 1, options);
321	    if (1 == status) {
322	      break;
323	    }
324	  }
325	
326	  /* Print an end to the file here */
327	  fp << "</fabric_bitstream>\n";
328	
329	  /* Close file handler */
330	  fp.close();
331	
332	  VTR_LOGV(options.verbose_output(),
333	           "Outputted %lu configuration bits to XML file: %s\n",
334	           fabric_bitstream.bits().size(), fname.c_str());
335	
336	  return status;
337	}
338	
339	} /* end namespace openfpga */
