34	 *******************************************************************/
35	template <class T>
36	int fpga_bitstream_template(T& openfpga_ctx, const Command& cmd,
37	                            const CommandContext& cmd_context) {
38	  CommandOptionId opt_verbose = cmd.option("verbose");
39	  CommandOptionId opt_no_time_stamp = cmd.option("no_time_stamp");
40	  CommandOptionId opt_write_file = cmd.option("write_file");
41	  CommandOptionId opt_read_file = cmd.option("read_file");
42	  CommandOptionId opt_unused_mux_config = cmd.option("unused_mux_config");
43	
44	  if (true == cmd_context.option_enable(cmd, opt_read_file)) {
45	    openfpga_ctx.mutable_bitstream_manager() = read_xml_architecture_bitstream(
46	      cmd_context.option_value(cmd, opt_read_file).c_str());
47	  } else {
48	    std::string unused_mux_config;
49	    unused_mux_config = cmd_context.option_enable(cmd, opt_unused_mux_config)
50	                          ? cmd_context.option_value(cmd, opt_unused_mux_config)
51	                          : "auto";
52	
53	    if (unused_mux_config != "auto" && unused_mux_config != "first" &&
54	        unused_mux_config != "last" && unused_mux_config != "unused_input") {
55	      VTR_LOG_ERROR(
56	        "Invalid unused_mux_config '%s'. Must be 'auto', 'first', 'last', or "
57	        "'unused_input'!\n",
58	        unused_mux_config.c_str());
59	      return CMD_EXEC_FATAL_ERROR;
60	    }
61	
62	    openfpga_ctx.mutable_bitstream_manager() =
63	      build_device_bitstream(g_vpr_ctx, openfpga_ctx, unused_mux_config,
64	                             cmd_context.option_enable(cmd, opt_verbose));
65	  }
66	
67	  overwrite_bitstream(openfpga_ctx.mutable_bitstream_manager(),
68	                      openfpga_ctx.bitstream_setting(),
69	                      cmd_context.option_enable(cmd, opt_verbose));
70	
71	  if (true == cmd_context.option_enable(cmd, opt_write_file)) {
72	    std::string src_dir_path =
73	      find_path_dir_name(cmd_context.option_value(cmd, opt_write_file));
74	
75	    /* Create directories */
76	    create_directory(src_dir_path, true,
77	                     cmd_context.option_enable(cmd, opt_verbose));
78	
79	    write_xml_architecture_bitstream(
80	      openfpga_ctx.bitstream_manager(),
81	      cmd_context.option_value(cmd, opt_write_file),
82	      !cmd_context.option_enable(cmd, opt_no_time_stamp));
83	  }
84	
85	  extract_device_non_fabric_bitstream(
86	    g_vpr_ctx, openfpga_ctx, cmd_context.option_enable(cmd, opt_verbose));
87	
88	  /* TODO: should identify the error code from internal function execution */
89	  return CMD_EXEC_SUCCESS;
