94	 *******************************************************************/
95	template <class T>
96	int build_fabric_bitstream_template(T& openfpga_ctx, const Command& cmd,
97	                                    const CommandContext& cmd_context) {
98	  CommandOptionId opt_verbose = cmd.option("verbose");
99	
100	  /* Build fabric bitstream here */
101	  openfpga_ctx.mutable_fabric_bitstream() = build_fabric_dependent_bitstream(
102	    openfpga_ctx.bitstream_manager(), openfpga_ctx.module_graph(),
103	    openfpga_ctx.module_name_map(), openfpga_ctx.arch().circuit_lib,
104	    openfpga_ctx.arch().config_protocol,
105	    cmd_context.option_enable(cmd, opt_verbose));
106	
107	  /* TODO: should identify the error code from internal function execution */
108	  return CMD_EXEC_SUCCESS;
109	}
