111	/********************************************************************
112	 * A wrapper function to call the write_fabric_bitstream() in FPGA bitstream
113	 *******************************************************************/
114	template <class T>
115	int write_fabric_bitstream_template(const T& openfpga_ctx, const Command& cmd,
116	                                    const CommandContext& cmd_context) {
117	  CommandOptionId opt_verbose = cmd.option("verbose");
118	  CommandOptionId opt_file = cmd.option("file");
119	  CommandOptionId opt_file_format = cmd.option("format");
120	  CommandOptionId opt_fast_config = cmd.option("fast_configuration");
121	  CommandOptionId opt_keep_dont_care_bits = cmd.option("keep_dont_care_bits");
122	  CommandOptionId opt_wl_decremental_order = cmd.option("wl_decremental_order");
123	  CommandOptionId opt_no_time_stamp = cmd.option("no_time_stamp");
124	  CommandOptionId opt_filter_value = cmd.option("filter_value");
125	  CommandOptionId opt_path_only = cmd.option("path_only");
126	  CommandOptionId opt_value_only = cmd.option("value_only");
127	  CommandOptionId opt_trim_path = cmd.option("trim_path");
128	
129	  /* Write fabric bitstream if required */
130	  int status = CMD_EXEC_SUCCESS;
131	
132	  VTR_ASSERT(true == cmd_context.option_enable(cmd, opt_file));
133	
134	  std::string src_dir_path =
135	    find_path_dir_name(cmd_context.option_value(cmd, opt_file));
136	
137	  /* Create directories */
138	  create_directory(src_dir_path, true,
139	                   cmd_context.option_enable(cmd, opt_verbose));
140	
141	  /* Check file format requirements */
142	  std::string file_format("plain_text");
143	  if (true == cmd_context.option_enable(cmd, opt_file_format)) {
144	    file_format = cmd_context.option_value(cmd, opt_file_format);
145	  }
146	
147	  /* Validate options */
148	  BitstreamWriterOption bitfile_writer_opt;
149	  bitfile_writer_opt.set_output_file_type(file_format);
150	  bitfile_writer_opt.set_output_file_name(
151	    cmd_context.option_value(cmd, opt_file));
152	  bitfile_writer_opt.set_time_stamp(
153	    !cmd_context.option_enable(cmd, opt_no_time_stamp));
154	  bitfile_writer_opt.set_verbose_output(
155	    cmd_context.option_enable(cmd, opt_verbose));
156	  bitfile_writer_opt.set_trim_path(
157	    cmd_context.option_enable(cmd, opt_trim_path));
158	  bitfile_writer_opt.set_path_only(
159	    cmd_context.option_enable(cmd, opt_path_only));
160	  bitfile_writer_opt.set_value_only(
161	    cmd_context.option_enable(cmd, opt_value_only));
162	  bitfile_writer_opt.set_fast_configuration(
163	    cmd_context.option_enable(cmd, opt_fast_config));
164	  bitfile_writer_opt.set_keep_dont_care_bits(
165	    cmd_context.option_enable(cmd, opt_keep_dont_care_bits));
166	  bitfile_writer_opt.set_wl_decremental_order(
167	    cmd_context.option_enable(cmd, opt_wl_decremental_order));
168	  if (cmd_context.option_enable(cmd, opt_filter_value)) {
169	    bitfile_writer_opt.set_filter_value(
170	      cmd_context.option_value(cmd, opt_filter_value));
171	  }
172	  if (!bitfile_writer_opt.validate(true)) {
173	    VTR_LOG_ERROR("Conflicts detected in options for bitstream writer!\n");
174	    return CMD_EXEC_FATAL_ERROR;
175	  }
176	
177	  if (bitfile_writer_opt.output_file_type() ==
178	      BitstreamWriterOption::e_bitfile_type::XML) {
179	    status = write_fabric_bitstream_to_xml_file(
180	      openfpga_ctx.bitstream_manager(), openfpga_ctx.fabric_bitstream(),
181	      openfpga_ctx.arch().config_protocol, bitfile_writer_opt);
182	  } else {
183	    VTR_ASSERT_SAFE(bitfile_writer_opt.output_file_type() ==
184	                    BitstreamWriterOption::e_bitfile_type::TEXT);
185	    /* By default, output in plain text format */
186	    status = write_fabric_bitstream_to_text_file(
187	      openfpga_ctx.bitstream_manager(), openfpga_ctx.fabric_bitstream(),
188	      openfpga_ctx.blwl_shift_register_banks(),
189	      openfpga_ctx.arch().config_protocol,
190	      openfpga_ctx.fabric_global_port_info(), bitfile_writer_opt);
191	  }
192	
193	  return status;
194	}
195	
196	/********************************************************************
197	 * A wrapper function to call the write_io_mapping() in FPGA bitstream
198	 *******************************************************************/
199	template <class T>
200	int write_io_mapping_template(const T& openfpga_ctx, const Command& cmd,
201	                              const CommandContext& cmd_context) {
202	  CommandOptionId opt_verbose = cmd.option("verbose");
203	  CommandOptionId opt_no_time_stamp = cmd.option("no_time_stamp");
204	  CommandOptionId opt_file = cmd.option("file");
205	
206	  /* Write fabric bitstream if required */
207	  int status = CMD_EXEC_SUCCESS;
208	
209	  VTR_ASSERT(true == cmd_context.option_enable(cmd, opt_file));
210	
211	  std::string src_dir_path =
212	    find_path_dir_name(cmd_context.option_value(cmd, opt_file));
213	
214	  /* Create directories */
215	  create_directory(src_dir_path, true,
